/** Build an ISO timestamp N days before DEMO_TODAY. */
function at(daysAgo: number, hour = 15): ISODateTime {
  return `${addDays(DEMO_TODAY, -daysAgo)}T${String(hour).padStart(2, "0")}:00:00.000Z`;
}

interface CheckInSpec {
  daysAgo: number;
  channel: Channel;
  functionItems: number[];
  pain: number;
  globalHealth: number;
  symptoms?: SymptomKey[];
  temperatureF?: number;
  note?: string;
}

interface MessageSpec {
  daysAgo: number;
  direction: "inbound" | "outbound";
  channel: Channel;
  body: string;
}

interface PatientSpec {
  id: string;
  name: string;
  age: number;
  sex: "F" | "M";
  phone: string;
  rung: LadderRung;
  cadenceDays: number;
  lastLabDate: ISODate | null;
  nextLabDueDate: ISODate | null;
  nextVisitDate: ISODate | null;
  treatment: string;
  channelPrefs: Channel[];
  thresholds?: ThresholdOverrides;
  checkIns: CheckInSpec[];
  messages?: MessageSpec[];
}

