function carePlanIdFor(patientId: string): string {
  return `cp-${patientId.replace(/^p-/, "")}`;
}

export function buildSeed(): ConstellateData {
  const protocol = raMtxProtocol();

  const patients: Patient[] = [];
  const enrollments: Enrollment[] = [];
  const carePlans: CarePlan[] = [];
  const checkIns: CheckIn[] = [];
  const messages: Message[] = [];
  const flags: Flag[] = [];

  for (const spec of SPECS) {
    const carePlanId = carePlanIdFor(spec.id);
    const enrollmentId = `en-${spec.id.replace(/^p-/, "")}`;

    const patient: Patient = {
      id: spec.id,
      name: spec.name,
      age: spec.age,
      sex: spec.sex,
      phone: spec.phone,
      conditions: ["RA"],
      enrollmentId,
      carePlanId,
    };

    const enrollment: Enrollment = {
      id: enrollmentId,
      patientId: spec.id,
      protocolId: RA_MTX_PROTOCOL_ID,
      consentAt: at(60),
      phone: spec.phone,
      conditions: ["RA"],
      treatment: spec.treatment,
      channelPrefs: spec.channelPrefs,
    };

    const carePlan: CarePlan = {
      id: carePlanId,
      patientId: spec.id,
      protocolId: RA_MTX_PROTOCOL_ID,
      target: "low",
      currentRung: spec.rung,
      cadenceDays: spec.cadenceDays,
      thresholds: spec.thresholds ?? {},
      nextLabDueDate: spec.nextLabDueDate,
      lastLabDate: spec.lastLabDate,
      nextVisitDate: spec.nextVisitDate,
    };

    // Build check-ins (+ their RAPID3 measures), oldest first.
    const patientCheckIns: CheckIn[] = spec.checkIns
      .slice()
      .sort((a, b) => b.daysAgo - a.daysAgo)
      .map((c, i) => {
        const id = `ci-${spec.id}-${i}`;
        const createdAt = at(c.daysAgo);
        const r = computeRapid3({
          functionItems: c.functionItems,
          pain: c.pain,
          globalHealth: c.globalHealth,
        });
        const measure: Measure = {
          id: `m-${id}`,
          checkInId: id,
          type: "RAPID3",
          value: r.value,
          components: r.components,
          bucket: r.bucket,
          createdAt,
        };
        return {
          id,
          patientId: spec.id,
          carePlanId,
          channel: c.channel,
          createdAt,
          answers: {
            rapid3: {
              functionItems: c.functionItems,
              pain: c.pain,
              globalHealth: c.globalHealth,
            },
            symptoms: {
              symptoms: c.symptoms ?? [],
              temperatureF: c.temperatureF,
              note: c.note,
            },
          },
          measures: [measure],
          status: "processed",
        } satisfies CheckIn;
      });

    // Messages
    const patientMessages: Message[] = (spec.messages ?? []).map((m, i) => ({
      id: `msg-${spec.id}-${i}`,
      patientId: spec.id,
      channel: m.channel,
      direction: m.direction,
      body: m.body,
      createdAt: at(m.daysAgo, 12 + i),
    }));

    // ── Generate this patient's open flags by running the engine ──
    const drafts = [];
    const latest = patientCheckIns.at(-1) ?? null;
    if (latest) {
      const measure = latest.measures[0];
      const previousMeasure =
        patientCheckIns.length > 1
          ? patientCheckIns[patientCheckIns.length - 2].measures[0]
          : null;
      drafts.push(
        ...evaluateCheckin({
          checkIn: latest,
          measure,
          previousMeasure,
          carePlan,
          protocol,
          patient,
        }),
      );
    }
    drafts.push(
      ...evaluateTime({
        carePlan,
        protocol,
        patient,
        asOf: DEMO_TODAY,
        lastCheckinAt: latest?.createdAt ?? null,
        latestBucket: latest?.measures[0].bucket,
      }),
    );

    for (const draft of dedupeDrafts([], drafts)) {
      const createdAt = draft.kind === "checkin" ? (latest?.createdAt ?? at(1)) : at(1, 9);
      flags.push(
        flagFromDraft(
          draft,
          `flag-${spec.id}-${draft.triggerId}`,
          createdAt,
          "open",
        ),
      );
    }

    patients.push(patient);
    enrollments.push(enrollment);
    carePlans.push(carePlan);
    checkIns.push(...patientCheckIns);
    messages.push(...patientMessages);
  }

  return {
    provider: PROVIDER,
    protocols: [protocol],
    patients,
    enrollments,
    carePlans,
    checkIns,
    messages,
    flags,
    actions: [],
    asOf: DEMO_TODAY,
  };
}
